module top_module(
        input   wire [31:0]   op1,
        input   wire [4:0]    shamt,
        input   wire [1:0]    operation,
        output  wire [31:0]   res
    );reg [31:0] invalid_shift_result;
    reg [31:0] sign_bits;

    assign res = invalid_shift_result;

    always @ *
    case (operation)
        2'b01: invalid_shift_result = (op1 <<  shamt); 
        2'b10: invalid_shift_result = (op1 >>  shamt); 
        2'b11: begin


          sign_bits = 32'hFFFFFFFF << (5'h1F - shamt);
          invalid_shift_result = (op1 >> shamt);
          invalid_shift_result = op1[31] ? sign_bits | invalid_shift_result : invalid_shift_result;
        end
        default: invalid_shift_result = 32'bx;
    endcase

endmodule
